// Token Store - simulates a token registry for service mesh
// ============================================================

type TokenStore struct {
	mu     sync.RWMutex
	tokens map[string]*ServiceIdentity
}

type ServiceIdentity struct {
	ServiceName string
	Namespace   string
	Roles       []string
	ExpiresAt   time.Time
}

func NewTokenStore() *TokenStore {
	ts := &TokenStore{
		tokens: make(map[string]*ServiceIdentity),
	}
	// Pre-populate with some service mesh tokens
	ts.RegisterToken("mesh-token-service-a", &ServiceIdentity{
		ServiceName: "service-a",
		Namespace:   "production",
		Roles:       []string{"reader", "writer"},
		ExpiresAt:   time.Now().Add(24 * time.Hour),
	})
	ts.RegisterToken("mesh-token-service-b", &ServiceIdentity{
		ServiceName: "service-b",
		Namespace:   "production",
		Roles:       []string{"reader"},
		ExpiresAt:   time.Now().Add(24 * time.Hour),
	})
	ts.RegisterToken("mesh-token-admin", &ServiceIdentity{
		ServiceName: "admin-service",
		Namespace:   "kube-system",
		Roles:       []string{"admin", "reader", "writer"},
		ExpiresAt:   time.Now().Add(24 * time.Hour),
	})
	return ts
}

func (ts *TokenStore) RegisterToken(token string, identity *ServiceIdentity) {
	ts.mu.Lock()
	defer ts.mu.Unlock()
	ts.tokens[token] = identity
}

func (ts *TokenStore) ValidateToken(token string) (*ServiceIdentity, error) {
	ts.mu.RLock()
	defer ts.mu.RUnlock()

	identity, exists := ts.tokens[token]
	if !exists {
		return nil, fmt.Errorf("token not found")
	}
	if time.Now().After(identity.ExpiresAt) {
		return nil, fmt.Errorf("token expired")
	}
	return identity, nil
}

