type AuthInterceptor struct {
	tokenStore     *TokenStore
	publicMethods  map[string]bool
	methodRoles    map[string][]string
}

func NewAuthInterceptor(tokenStore *TokenStore) *AuthInterceptor {
	return &AuthInterceptor{
		tokenStore: tokenStore,
		publicMethods: map[string]bool{
			"/mesh.MeshService/HealthCheck": true,
		},
		methodRoles: map[string][]string{
			"/mesh.MeshService/GetData":    {"reader", "admin"},
			"/mesh.MeshService/WriteData":  {"writer", "admin"},
			"/mesh.MeshService/AdminTask":  {"admin"},
			"/mesh.MeshService/StreamData": {"reader", "admin"},
		},
	}
}

func (ai *AuthInterceptor) extractToken(ctx context.Context) (string, error) {
	md, ok := metadata.FromIncomingContext(ctx)
	if !ok {
		return "", fmt.Errorf("no metadata in context")
	}

	// Check for authorization header (standard)
	values := md.Get("authorization")
	if len(values) == 0 {
		// Also check x-mesh-token for service mesh internal communication
		values = md.Get("x-mesh-token")
		if len(values) == 0 {
			return "", fmt.Errorf("no authorization token provided")
		}
		return values[0], nil
	}

	// Parse "Bearer <token>" format
	authHeader := values[0]
	if strings.HasPrefix(authHeader, "Bearer ") {
		return strings.TrimPrefix(authHeader, "Bearer "), nil
	}
	return authHeader, nil
}

func (ai *AuthInterceptor) extractRequestMetadata(ctx context.Context) map[string]string {
	result := make(map[string]string)
	md, ok := metadata.FromIncomingContext(ctx)
	if !ok {
		return result
	}

	// Extract tracing headers common in service mesh
	tracingHeaders := []string{
		"x-request-id",
		"x-trace-id",
		"x-span-id",
		"x-source-service",
		"x-destination-service",
	}
	for _, h := range tracingHeaders {
		if vals := md.Get(h); len(vals) > 0 {
			result[h] = vals[0]
		}
	}
	return result
}

func (ai *AuthInterceptor) authorize(ctx context.Context, method string) (*ServiceIdentity, error) {
	// Skip auth for public methods
	if ai.publicMethods[method] {
		return &ServiceIdentity{ServiceName: "anonymous"}, nil
	}

	token, err := ai.extractToken(ctx)
	if err != nil {
		return nil, status.Errorf(codes.Unauthenticated, "authentication failed: %v", err)
	}

	identity, err := ai.tokenStore.ValidateToken(token)
	if err != nil {
		return nil, status.Errorf(codes.Unauthenticated, "invalid token: %v", err)
	}

	// Check role-based authorization
	requiredRoles, exists := ai.methodRoles[method]
	if exists {
		hasRole := false
		for _, required := range requiredRoles {
			for _, role := range identity.Roles {
				if role == required {
					hasRole = true
					break
				}
			}
			if hasRole {
				break
			}
		}
		if !hasRole {
			return nil, status.Errorf(codes.PermissionDenied,
				"service %s does not have required role for %s (has: %v, needs one of: %v)",
				identity.ServiceName, method, identity.Roles, requiredRoles)
		}
	}

	return identity, nil
}

// Unary interceptor
func (ai *AuthInterceptor) UnaryInterceptor() grpc.UnaryServerInterceptor {
	return func(
		ctx context.Context,
		req interface{},
		info *grpc.UnaryServerInfo,
		handler grpc.UnaryHandler,
	) (interface{}, error) {
		start := time.Now()
		reqMeta := ai.extractRequestMetadata(ctx)

		log.Printf("[UNARY] Method: %s | RequestID: %s | TraceID: %s",
			info.FullMethod,
			reqMeta["x-request-id"],
			reqMeta["x-trace-id"],
		)

		identity, err := ai.authorize(ctx, info.FullMethod)
		if err != nil {
			log.Printf("[AUTH FAILED] Method: %s | Error: %v | Duration: %v",
				info.FullMethod, err, time.Since(start))
			return nil, err
		}

		// Inject identity into context for downstream use
		ctx = context.WithValue(ctx, contextKeyIdentity, identity)
		ctx = context.WithValue(ctx, contextKeyRequestMeta, reqMeta)

		resp, err := handler(ctx, req)

		log.Printf("[UNARY COMPLETE] Method: %s | Service: %s | Duration: %v | Error: %v",
			info.FullMethod, identity.ServiceName, time.Since(start), err)

		return resp, err
	}
}

// Stream interceptor
func (ai *AuthInterceptor) StreamInterceptor() grpc.StreamServerInterceptor {
	return func(
		srv interface{},
		ss grpc.ServerStream,
		info *grpc.StreamServerInfo,
		handler grpc.StreamHandler,
	) error {
		start := time.Now()
		ctx := ss.Context()
		reqMeta := ai.extractRequestMetadata(ctx)

		log.Printf("[STREAM] Method: %s | RequestID: %s | TraceID: %s",
			info.FullMethod,
			reqMeta["x-request-id"],
			reqMeta["x-trace-id"],
		)

		identity, err := ai.authorize(ctx, info.FullMethod)
		if err != nil {
			log.Printf("[AUTH FAILED] Method: %s | Error: %v | Duration: %v",
				info.FullMethod, err, time.Since(start))
			return err
		}

		// Wrap the stream to inject context values
		wrappedStream := &authenticatedStream{
			ServerStream: ss,
			ctx: context.WithValue(
				context.WithValue(ctx, contextKeyIdentity, identity),
				contextKeyRequestMeta, reqMeta,
			),
		}

		err = handler(srv, wrappedStream)

		log.Printf("[STREAM COMPLETE] Method: %s | Service: %s | Duration: %v | Error: %v",
			info.FullMethod, identity.ServiceName, time.Since(start), err)

		return err
	}
}

