func streamDataHandler(srv interface{}, stream grpc.ServerStream) error {
	s := srv.(*MeshServiceServer)
	ctx := stream.Context()
	identity := getIdentityFromContext(ctx)

	log.Printf("[StreamData] Service: %s starting stream", identity.ServiceName)

	// Send all stored data as a stream
	var count int32
	s.data.Range(func(key, value interface{}) bool {
		msg := &SimpleMessage{
			Fields: map[string]string{
				"key":   key.(string),
				"value": value.(string),
				"index": fmt.Sprintf("%d", count),
			},
		}
		if err := stream.SendMsg(msg); err != nil {
			return false
		}
		count++
		time.Sleep(100 * time.Millisecond) // Simulate processing
		return true
	})

	log.Printf("[StreamData] Service: %s | Sent %d items", identity.ServiceName, count)
	return nil
}

