// We need to implement encoding for our SimpleMessage type.
// In a real service mesh, you'd use protobuf.

type simpleCodec struct{}

func (c *simpleCodec) Marshal(v interface{}) ([]byte, error) {
	msg, ok := v.(*SimpleMessage)
	if !ok {
		return nil, fmt.Errorf("unsupported message type: %T", v)
	}
	// Simple encoding: key=value pairs separated by newlines
	var result string
	for k, v := range msg.Fields {
		result += k + "=" + v + "\n"
	}
	return []byte(result), nil
}

func (c *simpleCodec) Unmarshal(data []byte, v interface{}) error {
	msg, ok := v.(*SimpleMessage)
	if !ok {
		return fmt.Errorf("unsupported message type: %T", v)
	}
	if msg.Fields == nil {
		msg.Fields = make(map[string]string)
	}
	lines := strings.Split(string(data), "\n")
	for _, line := range lines {
		if line == "" {
			continue
		}
		parts := strings.SplitN(line, "=", 2)
		if len(parts) == 2 {
			msg.Fields[parts[0]] = parts[1]
		}
	}
	return nil
}

func (c *simpleCodec) Name() string {
	return "simple"
}

