func main() {
	// Suppress unused import errors
	_ = protogen.Options{}
	_ = &emptypb.Empty{}

	port := ":50051"

	// Initialize token store
	tokenStore := NewTokenStore()

	// Initialize auth interceptor
	authInterceptor := NewAuthInterceptor(tokenStore)

	// Create gRPC server with interceptors
	// Using insecure credentials since this is for service mesh internal
	// communication where mTLS is typically handled by the sidecar proxy (e.g., Envoy/Istio)
	server := grpc.NewServer(
		grpc.UnaryInterceptor(authInterceptor.UnaryInterceptor()),
		grpc.StreamInterceptor(authInterceptor.StreamInterceptor()),
	)

	// Register our service
	meshService := NewMeshServiceServer(tokenStore)
	server.RegisterService(&meshServiceDesc, meshService)

	// Enable reflection for debugging
	reflection.Register(server)

	// Start listener
	lis, err := net.Listen("tcp", port)
	if err != nil {
		log.Fatalf("Failed to listen on %s: %v", port, err)
	}

	log.Printf("Mesh gRPC service starting on %s", port)
	log.Printf("Registered tokens for: service-a, service-b, admin-service")

	// Start a goroutine to run test client calls
	go func() {
		time.Sleep(1 * time.Second)
		runTestClients(port)
	}()

	// Start serving
	if err := server.Serve(lis); err != nil {
		log.Fatalf("Failed to serve: %v", err)
	}
}

