func testUnaryCall(conn *grpc.ClientConn, method string, headers map[string]string, fields map[string]string) {
	ctx := context.Background()

	if headers != nil {
		md := metadata.New(headers)
		ctx = metadata.NewOutgoingContext(ctx, md)
	}

	req := &SimpleMessage{Fields: fields}
	resp := &SimpleMessage{Fields: make(map[string]string)}

	err := conn.Invoke(ctx, method, req, resp, grpc.ForceCodec(&simpleCodec{}))
	if err != nil {
		st, ok := status.FromError(err)
		if ok {
			log.Printf("  ERROR [%s]: %s", st.Code(), st.Message())
		} else {
			log.Printf("  ERROR: %v", err)
		}
		return
	}

	log.Printf("  SUCCESS: %v", resp.Fields)
}

func testStreamCall(conn *grpc.ClientConn, method string, headers map[string]string) {
	ctx := context.Background()

	if headers != nil {
		md := metadata.New(headers)
		ctx = metadata.NewOutgoingContext(ctx, md)
	}

	streamDesc := &grpc.StreamDesc{
		StreamName:   "StreamData",
		ServerStreams: true,
	}

	stream, err := conn.NewStream(ctx, streamDesc, method, grpc.ForceCodec(&simpleCodec{}))
	if err != nil {
		log.Printf("  ERROR creating stream: %v", err)
		return
	}

	// Send empty request to initiate
	if err := stream.SendMsg(&SimpleMessage{Fields: map[string]string{}}); err != nil {
		log.Printf("  ERROR sending: %v", err)
		return
	}
	if err := stream.CloseSend(); err != nil {
		log.Printf("  ERROR closing send: %v", err)
		return
	}

	// Receive stream items
	for {
		msg := &SimpleMessage{Fields: make(map[string]string)}
		err := stream.RecvMsg(msg)
		if err != nil {
			if err.Error() == "EOF" {
				break
			}
			st, ok := status.FromError(err)
			if ok && st.Code() != codes.OK {
				log.Printf("  STREAM ERROR [%s]: %s", st.Code(), st.Message())
			}
			break
		}
		log.Printf("  STREAM ITEM: %v", msg.Fields)
	}
}